mapper.select:
SELECT
    t.id as id,
    t.name as name,
    t.region_code as regionCode,
    t.tax_type as taxType,
    t.rate as rate,
    t.active as active,
    t.created_time as createdAt
FROM tax_rates t

    AND t.id = #{id}
    AND t.region_code = #{regionCode}
    AND t.tax_type = #{taxType}
    AND t.active = #{active}

${orderby} ${pagination}

SELECT count(*)
FROM tax_rates t

    AND t.id = #{id}
    AND t.region_code = #{regionCode}
    AND t.tax_type = #{taxType}
    AND t.active = #{active}
